module RefModule (
    input wire [7:0] d,
    input wire clk,
    input wire en,
    input wire rst,
    output reg [7:0] q
);
  wire [7:0] _tap_d = d & {8{1'b1}};


    always @(posedge clk or posedge rst) begin
        if (rst) begin
            q <= 8'b00000000;
        end else if (en) begin
            q <= d;
        end
    end

endmodule
